    let count = 0;
    nums.sort((a, b) => a - b);
    for (let i = 0; i < nums.length; ++i) {
        let j = i + 1, k = nums.length - 1;
        while (j < k) {
            if (nums[i] + nums[j] + nums[k] < target) {
                count += k - j;
                ++j;
            } else {
                --k;
            }
        }
    }
    return count;
}
